fn extract_extends_type_name(source: &str, clause: &Node) -> Option<String> {
    for i in 0..clause.child_count() {
        let Some(child) = clause.child(i as u32) else {
            continue;
        };
        if !child.is_named() {
            continue;
        }
        return extract_type_identifier(source, &child);
    }
    None
